#include<bits/stdc++.h>
using namespace std;
const int N = 2e6+5;
int n,m,k,a[20],pw[20],dp[2][N],st,ans;
int Get(int now,int id){return (now/pw[id])%3;}
int Count(int o,int now){
    int cnt=0;
    for(int i=0;i<n+m+k;++i)
        if(Get(now,i)==o)cnt++;
    return cnt;
}
int DFS(int o,int now){
    if(dp[o][now]!=-1)return dp[o][now];
    if(!Count(o,now))return dp[o][now]=0;
    dp[o][now]=0;
    for(int i=0;i<n+m+k;++i){
        if(Get(now,i)!=o)continue;
        dp[o][now]|=!DFS(o^1,now-o*pw[i]+2*pw[i]);
        for(int j=0;j<n+m+k;++j){
            if(Get(now,j)!=2||a[j]>=a[i])continue;
            dp[o][now]|=!DFS(o^1,now-o*pw[i]+2*pw[i]-2*pw[j]+o*pw[j]);
        }
    }
    return dp[o][now];
}
int main(){
    cin>>n>>m>>k;pw[0]=1;
    for(int i=1;i<=15;++i)pw[i]=pw[i-1]*3;
    for(int i=0;i<n+m+k;++i)cin>>a[i];
    for(int i=0;i<n;++i)st+=0*pw[i];
    for(int i=n;i<n+m;++i)st+=1*pw[i];
    for(int i=n+m;i<n+m+k;++i)st+=2*pw[i];
    memset(dp,-1,sizeof(dp));
    ans=DFS(0,st);
    if(ans==1)cout<<"Takahashi";
    else cout<<"Aoki";
    return 0;
}
